<span class="line">        TSubclassOf<span class="token operator">&lt;</span>UGameplayEffect<span class="token operator">&gt;</span> EffectClass<span class="token punctuation">,</span> <span class="token keyword">float</span> Level<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
